import{_ as a,c as o,o as t,ae as e}from"./chunks/framework.BvcDoAct.js";const k=JSON.parse('{"title":"01 SOTA的故事","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/RockInOnJapan_BF/1_SOTA.md","filePath":"zh-cn/RockInOnJapan_BF/1_SOTA.md"}'),n={name:"zh-cn/RockInOnJapan_BF/1_SOTA.md"};function c(s,p,r,T,i,_){return t(),o("div",null,[...p[0]||(p[0]=[e('<h1 id="_01-sota的故事" tabindex="-1">01 SOTA的故事 <a class="header-anchor" href="#_01-sota的故事" aria-label="Permalink to &quot;01 SOTA的故事&quot;">​</a></h1><h2 id="成为提出全新风格、独一无二的艺术家-——-舞蹈与音乐交织的四年" tabindex="-1">成为提出全新风格、独一无二的艺术家 —— 舞蹈与音乐交织的四年 <a class="header-anchor" href="#成为提出全新风格、独一无二的艺术家-——-舞蹈与音乐交织的四年" aria-label="Permalink to &quot;成为提出全新风格、独一无二的艺术家 —— 舞蹈与音乐交织的四年&quot;">​</a></h2><p>●（一边给他看当时的文章）这是3年前的个人采访。</p><p>“哇，好羞耻啊。我从那之后减了8公斤。”</p><p>● 厉害啊。在作为BE:FIRST的SOTA减重8公斤的这段时间里，你有什么样的感受？</p><p>“无论是对音乐的思考深度，还是生活本身，我都觉得自己是非常有意识地在成长。不过，事务所的氛围、和社长的距离感、成员之间的关系这些周围的环境，其实并没有太大的变化，所以反而很少会觉得‘已经过去很久了’。从当时开始，我就一直被允许表达自己在音乐上的想法，然后这些想做的事情也逐渐能够落实到作品发布上。一路走来几乎没有什么压力，这大概就是让我觉得‘这4年转瞬即逝’的原因吧。”</p><p>● 作为艺术家的欲望，或者说“我们就是想做这个”的那种推动力，我感觉一直是由SOTA在引领的，而现在也逐渐变成了整个团体更加坚定的方向。3年前的采访里，可以很直接地感受到你在作为舞者建立职业生涯后，踏入艺术家世界、拿起麦克风的喜悦，以及从此要作为艺术家去战斗的觉悟。</p><p>“嗯。”</p><p>● 正因为你当时明确感受到舞者和艺术家的区别，所以一开始就聚焦在“作为艺术家能做什么”。那现在你是怎么思考这个问题的？</p><p>“舞者和艺术家的区别，在我心里变得越来越清晰了。无论是环境，还是对音乐的表达方式，真的完全不一样。能够以艺术家的身份去表达音乐，我觉得真的太好了。随着时间的积累，我注意到的细节也越来越多，越是察觉这些，就越有这种感觉。”</p><p>● 在当时的采访中，你说过：<strong>“当我在BE:FIRST这个地方拿起麦克风的时候，会觉得自己无所不能！”</strong> 那种解放感和高涨的情绪很强烈，现在这种感觉还在吗？</p><p>“还在。尤其是最近开始做DTM之后更是这样。可能是舞者的职业病吧，我脑子里真的存着‘那些歌’，多到要命。也不是刻意去挖掘的，就是在舞池里放过的、在battle里听过的，那些一直留在记忆里的音乐特别多。最近在用DTM做歌的时候，我会从那些记忆里的曲子里拿来kick的位置，贴到适合我跳舞的位置，这个过程特别有意思。一边听着click一边动身体，然后说‘这里要来两下吧’，就把kick放进去，hi-hat也是一边说‘这里这样走吧’，一边按Command+D（笑）。现在我可以把真正想跳的声音做出来，这点让一切变得更有趣了。”</p><p>● 很有意思。输出都是舞蹈，但过程完全相反——不是跟着已有的声音去跳，而是去创造自己想跳的声音。</p><p>“基本就是灵感驱动吧。社长也说这种‘先有舞再做音乐’的方式很有趣，我自己也觉得很好玩。”</p><p>● 这可能就是艺术家SOTA的特色或武器吧。 “如果是那样我会很开心。”</p><p>● 刚出道的时候，大家经常说“跳舞的SOTA”“说唱的SOTA”，但现在你明显在不断突破这些标签。你对自己的认知有变化吗？</p><p>“这么一说，好像确实。以前社长还会特意说‘这次有你的唱歌部分哦’，但不知不觉也没有了。现在有hook也已经是理所当然的事了。前阵子还拍了THE FIRST TAKE，对唱歌的紧张和不安也减少了。变得更像是单纯和成员一起享受的时间，这点我特别开心。但另一方面，我也一直在精进舞蹈，所以不想抹平那个差距。专精舞蹈本来就是优势，不需要去对齐。所以我一直在摸索、研究，这4年从人生角度来说，也是我舞蹈提升最多的4年。获得了各种感性，也从没像现在这样感受到作为舞者的成长。”</p><blockquote><p>这是久违地能自由享受舞蹈的4年，也因此有了各种发现，听到了更多不同的声音</p></blockquote><p>● 你是因为什么而成长的？</p><p>“原因有很多。以前做舞者的时候我真的特别用脑，尤其是比赛期间，身体是肌肉酸痛，脑子也像肌肉酸痛一样，每天都在思考。比如鼓点要用popping去取，旋律线要用流行的south风格去抓之类的。每天都有不断更新的束缚。但现在真的可以随心所欲地去做。不再在意比赛或评价，也没有那种‘会不会给招牌抹黑’的压力。这4年是久违地自由享受舞蹈的时间，但反而因此有了更多发现，听到了更多声音……再加上开始唱歌、做音乐之后，能听到以前听不到的东西。虽然很难用语言表达，但我对音乐的理解已经在不知不觉中发生了很大的变化。比如freestyle的时候特别明显，我开始用以前不会用的身体连接方式了。以前我freestyle多半是抓鼓点，但现在会听到和弦，比如一小节里有三个和弦时，会觉得‘这是minor’‘这是C’‘这个旋律挺性感的’，然后按这种感觉去跳。只听鼓点开始跳的情况变少了。即使是freestyle，感受也完全不同，这点很有意思。”</p><p>● 等于舞蹈的概念变了。</p><p>“更有深度了。以前我只把合成器当作人声的一部分去听，只是在纠结底下的kick和hat选哪个，但现在会清楚听到‘这里是合成器’‘这里是吉他’，然后从那里扩展理解，跳出来的舞也完全不同，范围也变大了。”</p><p>● 如果实际对比舞蹈，差异应该比语言更明显，这真的很重要。</p><p>“特别重要。很多人比如RIEHATA都会说我‘舞跳得更好了’，但其实我没怎么练舞，只是能听到的声音变多了。就像做料理一样，在原有的素材库之外，又增加了可以实时调用的材料和操作的案板。RIEHATA会说‘听不懂’（笑），但我现在就是这种感觉在跳。”</p><p>● 等于是身体意识到了“舞蹈本身也是音乐”。</p><p>“真的就是这样。虽然听起来有点中二（笑）。以前声音是混在一起听的，现在却能像看到波形一样分轨，比如这个是绿色，这个是蓝色。当你能把混在一起的声音分开感知，就会觉得把它们当作一个整体去跳其实很浅。比如（边做动作）第一个音用手去取，下一段和弦是不是应该用身体去取……我现在是这么去看舞蹈的。”</p><p>● 正因为作为艺术家积累了这些经验，才看到了这些。</p><p>“真的很感恩。”</p><p>● 这不仅是技术问题，更是你的人生。是你把作为舞者积累的一切，与成为艺术家的轨迹连接起来的方式。</p><p>“我当初就是觉得艺术家的世界一定更深才跳进去的，但没想到比想象中还深。让我体验到了很多超出预期的东西，也获得了当时无法想象的感受，真的很好。”</p><p>● 而且在说唱上也是一样吧，变化很明显。</p><p>“嗯。舞蹈方面我是‘不想再烦恼了’的想法，但说唱我一直是有意识地在重视。”</p><p>● 3年前你说过“因为可以像跳舞一样把语言融入音乐，所以适合说唱”，所以随着舞蹈观念变化，说唱的表达也变了。简单说就是，说唱变得更像“歌”了。</p><p>“确实。最近尤其如此。最开始我很喜欢像鼓一样去抓节奏，但现在学了很多，也随着BE:FIRST整体氛围的变化，会更有意识地去‘唱着说唱’。”</p><p>● 听“I Want You Back”的时候，我觉得特别好的一点是你两段verse的表情完全不同。</p><p>“那是很关键的位置，所以花了不少心思。我有在研究情绪变化，以及说唱中可以呈现的情感。”</p><p>● 那种变化本身就成了歌曲的戏剧性，很音乐化。那你对翻唱“I Want You Back”这件事怎么看？我觉得这个问题必须问你。</p><p>“其实还没有完全实感。但唱的时候会在好的意义上忘记Jackson 5。本来我以为会因为‘在表演Jackson 5’而被情绪压倒，但最后能感觉到它变成了BE:FIRST的东西，这让我特别开心。虽然是致敬翻唱，但既然现在技术已经发展到这个程度，如果只是出于憧憬去做，反而有点对不起原作。所以如果接过这个接力棒，就必须在某些地方以BE:FIRST的方式超越。这点我现在也在努力。最终，如果有人听了我们的版本去找原曲，那我会很开心。我相信只要听一遍原曲，就一定能感受到它的魅力。所以现在我就是全力以BE:FIRST的方式去完成它。”</p><blockquote><p>我们一直在传递“青春”。“I Want You Back”的翻唱，是一首随着演绎不断增强说服力与厚度的作品</p></blockquote><p>● 在你的solo曲“Chill with you”里有一句“拯救了我的Jacksons＝英雄”，写这句的时候已经确定要翻唱了吗？</p><p>“已经确定了。那段时间真的特别开心，每天都飘着，结果就写进歌词了（笑）。”</p><p>● 实际上声音里也有这种情感。</p><p>“因为真的很尊敬他们，所以那种开心自然流露在录音里。我觉得这样反而很好。”</p><p>● 那对你来说，Jackson 5为什么是“英雄”？</p><p>“是我喜欢上洋乐的契机。从小我妈就一直放Jackson 5、TLC，我那时候其实很讨厌听不懂日语的歌，只想听宝可梦主题曲（笑）。但她不让，还老放同一首。在这种环境里，只有‘I Want You Back’打动了我。我记得很清楚，小学二年级春天，我和妈妈吵架哭了，因为在海边弄丢了麦当劳玩具，被骂还被要求去找。晚上八点，我觉得像半夜一样黑，还去海边找。”</p><p>● 记得好清楚。</p><p>“第二天周六，我一个人在家，无聊就翻DVD，找到‘I Want You Back’，看着就哭了。那是我第一次因为音乐哭。虽然听不懂，但能感受到幸福感，从那之后就迷上了。后来疯狂去挖，从Michael的资料到现场，再到致敬演出，一直追着他。他是我人生前半段不可或缺的存在。所以这次我也希望听的人能有那种感觉——一种说不清的幸福感。”</p><p>● 20年后用自己的方式去演绎这样的歌曲，这是很惊人的故事，也像是在肯定你的人生。</p><p>“真的有被肯定的感觉。我一直觉得，我们这一代不能让好的东西变成小众。《Mainstream》也是这样，我们一直在传递青春。这首歌也会随着我们不断演绎，变得更有说服力和厚度。”</p><p>● 这个翻唱是你提出的吗？</p><p>“是在和社长一起泡桑拿时聊的。我觉得作为boy band，如果要翻唱，这首绝对不能少，再加上个人情感，就提了出来。社长说‘不错’，我就觉得‘有戏’，然后猛推（笑）。”</p><p>● 这一定会成为你和BE:FIRST艺术生涯中的高光之一。</p><p>“绝对是高光。希望葬礼上也能放（笑）。”</p><p>● 夸张点说，你成为艺术家就是为了实现这种人生的肯定。</p><p>“谢谢。”</p><p>● 听你讲下来，无论是舞蹈还是说唱，其实都是一段“肯定自我人生”的旅程。</p><p>“我一直都想肯定自己。虽然我挺乐观，但做选择时都会想‘哪一个更能让我肯定自己’。比如舞蹈风格，我不喜欢竞争，如果有自己的风格，就算被比较，也可以说‘这只是喜好’。这种想法到现在也没变。”</p><p>● 在这一点上，你和SKY-HI很有共鸣。你谈到他时，有点像朋友，也有点像对手，很微妙。</p><p>“确实。我们经常会说，比起‘BE:FIRST是最好的’，更想做‘只有BE:FIRST在做的东西’。在音乐方向上，我们的核心理念很一致。所以关键决策时他也会让我来定。比如讨论方向后，会突然问‘那到底做什么？’把最重要的部分交给我。我一方面很开心，但也会想‘万一失败是不是我的锅（笑）’。”</p><p>● 哈哈！</p><p>“但像《Mainstream》就是这么诞生的。有成功经验，所以以后也想继续这样挑战。”</p><p>● 这不仅是信任，更是一种共鸣。不断创造全新的东西，并把它变成绝对正确，这也是BE:FIRST的核心。</p><p>“嗯，是的。”</p><p>● 顺便问，现在还会被称为“前舞蹈世界冠军”吗？</p><p>“少很多了。现在再说都太‘前’了（笑）。现在的我跳得更好，也有了超越头衔的东西。甚至让我想再去拿一次冠军。”</p><p>● 太帅了。</p><p>“社长好像真的想让我这两年去认真挑战。我一直想做，所以应该会去争一次。输了的话不好意思（笑）。”</p><p>● 哈哈。那个头衔不是标签，而是勋章。关键是如何用更浓的颜色去覆盖它。</p><p>“是的。以现在的状态去比赛，我觉得一定能赢。因为这种听音方式应该很少见。如果认真编一套‘为赢而生’的编舞，应该会很厉害。想趁这种感觉还在的时候去做。”</p>',69)])])}const S=a(n,[["render",c]]);export{k as __pageData,S as default};
